public class BoyerMooreTest {
    @Test
    public void suffixesTest() {
        // Preconditions
        String target = "HERE IS A SIMPLE EXAMPLE";
        String template = "EXAMPXA";

        // Execute suffix calculation method
        int[] computedSuffixes = BoyerMoore.suffixes(template);

        // Expected suffix array for "EXAMPXA" based on algorithm logic
        // The algorithm calculates the length of matching suffix ending at each position.
        // For "EXAMPXA" (indices 0-6):
        // Position 6 (A): Compare pat[6]='A' with pat[6] -> match, j moves to 5.
        //   Compare pat[5]='X' with pat[6]? No, stop. suffixes[6] = 6-5 = 1.
        // Position 5 (X): Compare pat[5]='X' with pat[6]? No, stop. suffixes[5] = 5-5 = 0.
        // Position 4 (P): Compare pat[4]='P' with pat[6]? No, stop. suffixes[4] = 4-4 = 0.
        // Position 3 (M): Compare pat[3]='M' with pat[6]? No, stop. suffixes[3] = 3-3 = 0.
        // Position 2 (A): Compare pat[2]='A' with pat[6]? Yes, j moves to 1.
        //   Compare pat[1]='X' with pat[5]? Yes, j moves to 0.
        //   Compare pat[0]='E' with pat[4]? No, stop. suffixes[2] = 2-0 = 2.
        // Position 1 (X): Compare pat[1]='X' with pat[6]? No, stop. suffixes[1] = 1-1 = 0.
        // Position 0 (E): Compare pat[0]='E' with pat[6]? No, stop. suffixes[0] = 0-0 = 0.
        // Result: [0, 0, 2, 0, 0, 0, 1]
        int[] expectedSuffixes = new int[]{0, 0, 2, 0, 0, 0, 1};

        // Verify computed suffix array matches expected
        assertArrayEquals("Suffix array for EXAMPXA is incorrect", 
                         expectedSuffixes, computedSuffixes);

        // Print computed suffix array for confirmation
        System.out.print("Computed suffix array: ");
        for (int i = 0; i < computedSuffixes.length; i++) {
            System.out.print(computedSuffixes[i]);
            if (i < computedSuffixes.length - 1) {
                System.out.print(", ");
            }
        }
        System.out.println();
    }
}

