public static BufferedReader bufferedReader (String file){
        return new BufferedReader(new InputStreamReader(new FileInputStream(file)));
    }
}

ReplaceSelectionSort{
String prepareSuffixedFile (String original, String suffix){
        String flag = "-wait-";

        if (!original.contains(flag)) {
            return original + suffix + 0;
        }

        String[] parts = original.split(flag);
        String name = parts[0];
        int seq = Integer.parseInt(parts[1]) + 1;

        return name + suffix + seq;
    }
}

public void sort(String original) throws IOException {
    long countLines = FileUtil.countLines(original);
    // 置换-选择拆分成大小不一的顺串文件
    ReplaceSelectionSort repSelSorter = new ReplaceSelectionSort((int) (countLines / 5));

    List<String> seqfilesList = new ArrayList<>();
    repSelSorter.splitToSeqfile(original, seqfilesList);

    // 归并初始顺串
    merge(seqfilesList);
}

