        assertEquals(Integer.valueOf(18), skipList.get("8"));
        assertEquals(Integer.valueOf(16), skipList.get("6"));
        assertEquals(Integer.valueOf(14), skipList.get("4"));

        // Expected Results 3: The skip list's size increases by four entries.
        assertEquals(4, skipList.size);

        // Expected Results 2: The skip list's structure maintains proper connections between layers.
        // Traverse the bottom level to verify order.
        SkipListEntry cursor = skipList.head;
        // Move down to the bottom level.
        while (cursor.down != null) {
            cursor = cursor.down;
        }
        // Now cursor is at the bottom level head. Move right past the head sentinel (INFINITE_NEGATIVE).
        cursor = cursor.right;
