        // Check that all expected keys are present, regardless of order.
        assertTrue(actualKeys.contains("4"));
        assertTrue(actualKeys.contains("6"));
        assertTrue(actualKeys.contains("8"));
        assertTrue(actualKeys.contains("10"));
        assertEquals(4, actualKeys.size()); // Ensure no extra keys.

