<COVER>            if (entryCoursor.down != null) {
<COVER>                entryCoursor = entryCoursor.down;
            } else {
                break; // 已经是最下层，退出查找循环
            }
        }

        // 最下层找到符合的节点或前驱节点，满足 entryCoursor<= key
<COVER>        return entryCoursor;
    }

    /**
     * 获取指定的value
     */
    public Integer get(String key) {
<COVER>        SkipListEntry foundEntry = findEntry(key);

<COVER>        if (foundEntry.key.equals(key)) { // key相等，表示是对应节点
<COVER>            return foundEntry.value;
        } else { // 不相等说明只查找到了前驱节点
            return null;
        }
    }

    /**
     * 添加kv
     */
    public Integer put(String key, Integer value) {
        // 找到最底层的对应节点或前驱节点
<COVER>        SkipListEntry prev = findEntry(key);

        // 如果跳跃表中存在含有key值的节点，则进行value的修改操作即可完成
<COVER>        if (prev.key.equals(key)) {
