    /**
     * 顺时针关联插入法
     */
    private SkipListEntry insertByClockwise(String key, Integer value, SkipListEntry prev) {
<COVER>        SkipListEntry toPutEntry = new SkipListEntry(key, value);

        // 后继节点
<COVER>        SkipListEntry suceed = prev.right;
        // 指向后继
<COVER>        toPutEntry.right = suceed;
        // 后继指向该节点
<COVER>        suceed.left = toPutEntry;
        // 指向前驱
<COVER>        toPutEntry.left = prev;
        // 前驱指向该节点
<COVER>        prev.right = toPutEntry;

<COVER>        return toPutEntry;
