    private void addEmptyLevel() {
        SkipListEntry newHead, newTail;

<COVER>        newHead = new SkipListEntry(SkipListEntry.INFINITE_NEGATIVE, null);
<COVER>        newTail = new SkipListEntry(SkipListEntry.INFINITE_POSITIVE, null);

<COVER>        newHead.right = newTail;
<COVER>        newTail.left = newHead;

        // 上下层关联
<COVER>        newHead.down = head;
<COVER>        newTail.down = tail;
<COVER>        head.up = newHead;
<COVER>        tail.up = newTail;

